import pytest
from your_module import binary_search  # Replace 'your_module' with actual module name


class TestBinarySearchHappyPath:
    """Tests for successful target finding scenarios."""

    def test_target_at_beginning(self):
        """Test when target is at the start of the array."""
        assert binary_search([1, 3, 5, 7, 9], 1) == 0

    def test_target_at_end(self):
        """Test when target is at the end of the array."""
        assert binary_search([1, 3, 5, 7, 9], 9) == 4

    def test_target_in_middle(self):
        """Test when target is in the middle of the array."""
        assert binary_search([1, 3, 5, 7, 9], 5) == 2

    def test_target_in_left_half(self):
        """Test when target is in the left half of the array."""
        assert binary_search([1, 3, 5, 7, 9], 3) == 1

    def test_target_in_right_half(self):
        """Test when target is in the right half of the array."""
        assert binary_search([1, 3, 5, 7, 9], 7) == 3

    def test_large_sorted_array(self):
        """Test with a large sorted array."""
        arr = list(range(0, 10000, 2))
        assert binary_search(arr, 5000) == 2500


class TestBinarySearchEdgeCases:
    """Tests for edge cases and boundary conditions."""

    def test_single_element_found(self):
        """Test array with single element that matches target."""
        assert binary_search([5], 5) == 0

    def test_single_element_not_found(self):
        """Test array with single element that doesn't match target."""
        assert binary_search([5], 3) == -1

    def test_two_elements_first_match(self):
        """Test array with two elements, first matches."""
        assert binary_search([1, 2], 1) == 0

    def test_two_elements_second_match(self):
        """Test array with two elements, second matches."""
        assert binary_search([1, 2], 2) == 1

    def test_two_elements_no_match(self):
        """Test array with two elements, no match."""
        assert binary_search([1, 2], 3) == -1

    def test_negative_numbers(self):
        """Test with negative numbers in sorted array."""
        assert binary_search([-9, -5, -1, 0, 3, 7], -5) == 1

    def test_all_negative_numbers(self):
        """Test with all negative numbers."""
        assert binary_search([-10, -8, -6, -4, -2], -6) == 2

    def test_mixed_positive_negative(self):
        """Test with mixed positive and negative numbers."""
        assert binary_search([-5, -2, 0, 3, 8], 0) == 2

    def test_target_smaller_than_all_elements(self):
        """Test when target is smaller than all array elements."""
        assert binary_search([5, 10, 15, 20], 1) == -1

    def test_target_larger_than_all_elements(self):
        """Test when target is larger than all array elements."""
        assert binary_search([5, 10, 15, 20], 25) == -1

    def test_target_between_elements(self):
        """Test when target falls between existing elements."""
        assert binary_search([1, 3, 5, 7, 9], 4) == -1


